import torch
import torch.nn as nn
import numpy as np

class StandardScaler:
    def __init__(self):
        self.mean_ = None
        self.std_ = None

    def fit(self, X: torch.Tensor):
        self.mean_ = X.mean(dim=0)
        self.std_ = X.std(dim=0) + 1e-8
        return self

    def transform(self, X: torch.Tensor) -> torch.Tensor:
        return (X - self.mean_) / self.std_

    def fit_transform(self, X: torch.Tensor) -> torch.Tensor:
        return self.fit(X).transform(X)


class PCA:
    def __init__(self, n_components):
        self.n_components = n_components
        self.components_ = None
        self.mean_ = None

    def fit(self, X: torch.Tensor):
        self.mean_ = X.mean(dim=0)
        X_c = X - self.mean_
        cov = (X_c.T @ X_c) / (X_c.shape[0] - 1)
        eigvals, eigvecs = torch.linalg.eigh(cov)
        idx = torch.argsort(eigvals, descending=True)
        eigvecs = eigvecs[:, idx]
        self.components_ = eigvecs[:, :self.n_components].T
        return self

    def transform(self, X: torch.Tensor) -> torch.Tensor:
        return (X - self.mean_) @ self.components_.T

    def fit_transform(self, X: torch.Tensor) -> torch.Tensor:
        return self.fit(X).transform(X)


class LogisticRegression(nn.Module):
    def __init__(self, n_features, lr=0.1, n_iter=1000):
        super().__init__()
        self.linear = nn.Linear(n_features, 1)
        self.lr = lr
        self.n_iter = n_iter

    def fit(self, X: torch.Tensor, y: torch.Tensor):
        optimizer = torch.optim.SGD(self.parameters(), lr=self.lr)
        loss_fn = nn.BCEWithLogitsLoss()
        y_t = y.float().unsqueeze(1)
        for _ in range(self.n_iter):
            optimizer.zero_grad()
            logits = self.linear(X)
            loss = loss_fn(logits, y_t)
            loss.backward()
            optimizer.step()
        return self

    @torch.no_grad()
    def predict(self, X: torch.Tensor) -> torch.Tensor:
        logits = self.linear(X)
        return (torch.sigmoid(logits) >= 0.5).squeeze(1).long()


class Pipeline:
    def __init__(self, n_components=2, lr=0.1, n_iter=1000):
        self.scaler = StandardScaler()
        self.pca = PCA(n_components=n_components)
        self.lr = lr
        self.n_iter = n_iter
        self.clf = None

    def fit(self, X, y):
        X_t = torch.tensor(X, dtype=torch.float32) if not isinstance(X, torch.Tensor) else X.float()
        y_t = torch.tensor(y, dtype=torch.float32) if not isinstance(y, torch.Tensor) else y.float()
        X_scaled = self.scaler.fit_transform(X_t)
        X_pca = self.pca.fit_transform(X_scaled)
        self.clf = LogisticRegression(X_pca.shape[1], lr=self.lr, n_iter=self.n_iter)
        self.clf.fit(X_pca, y_t)
        return self

    def predict(self, X):
        X_t = torch.tensor(X, dtype=torch.float32) if not isinstance(X, torch.Tensor) else X.float()
        X_scaled = self.scaler.transform(X_t)
        X_pca = self.pca.transform(X_scaled)
        return self.clf.predict(X_pca).numpy()
